<script setup lang="ts">
import { computed,onMounted,ref } from 'vue'; import { useHealthCasesStore } from '@/stores/healthCases'; import PriorityBadge from '@/components/health/PriorityBadge.vue'; import type { HealthCase,HealthCaseStatus } from '@/types'
const store=useHealthCasesStore(); const selected=ref<HealthCase|null>(null); const note=ref(''); onMounted(async()=>{await Promise.all([store.loadCases(),store.loadActions()])}); const emergency=computed(()=>store.cases.filter(c=>c.priority_level==='EMERGENCY').length); const pending=computed(()=>store.pendingReview.length)
async function change(status:HealthCaseStatus){if(!selected.value)return;await store.updateStatus(selected.value.id,status,note.value);selected.value=store.cases.find(c=>c.id===selected.value?.id)||null;note.value=''}
</script>
<template><div class="page"><header><div><span>🛡️ Operaciones</span><h1>Panel de atención</h1><p>Revisa alertas, aprueba acciones y documenta el seguimiento humano.</p></div></header><section class="stats"><article><strong>{{store.cases.length}}</strong><span>Casos totales</span></article><article><strong>{{emergency}}</strong><span>Alertas rojas</span></article><article><strong>{{pending}}</strong><span>Pendientes de revisión</span></article></section><section class="workspace"><div class="list card"><div class="card-header">Cola de casos</div><button v-for="item in store.cases" :key="item.id" :class="{active:selected?.id===item.id}" @click="selected=item"><div><strong>{{item.reason||'Caso sin título'}}</strong><small>{{item.profiles?.full_name||'Ciudadano'}} · {{item.status}}</small></div><PriorityBadge :priority="item.priority_level"/></button><p v-if="!store.cases.length" class="empty">No hay casos todavía.</p></div><div class="detail card"><div class="card-header">Revisión humana</div><div v-if="!selected" class="empty">Selecciona un caso.</div><template v-else><div class="card-body"><PriorityBadge :priority="selected.priority_level" :score="selected.priority_score"/><h2>{{selected.reason}}</h2><p>{{selected.summary}}</p><dl><dt>Estado</dt><dd>{{selected.status}}</dd><dt>Sector</dt><dd>{{selected.sector||'No indicado'}}</dd><dt>Señales</dt><dd>{{selected.warning_signs.join(', ')||'Ninguna registrada'}}</dd></dl><textarea v-model="note" class="form-input" rows="4" placeholder="Nota del operador..."/><div class="actions"><button class="btn btn-secondary" @click="change('ORIENTED')">Marcar orientado</button><button class="btn btn-primary" @click="change('REFERRED')">Registrar derivación</button><button class="btn btn-secondary" @click="change('RESOLVED')">Resolver</button><button class="btn btn-danger" @click="change('CLOSED')">Cerrar</button></div></div></template></div></section></div></template>
<style scoped>.page{padding:2rem;max-width:1250px;margin:auto}.page header span{color:var(--color-teal-dark);font-size:.8rem;font-weight:800}.page h1{color:var(--color-navy)}.page header p{color:var(--color-gray-500)}.stats{display:grid;grid-template-columns:repeat(3,1fr);gap:1rem;margin:1.2rem 0}.stats article{background:#fff;border:1px solid #e2e8f0;border-radius:14px;padding:1rem;display:flex;flex-direction:column}.stats strong{font-size:1.7rem;color:#082f49}.stats span{color:#64748b}.workspace{display:grid;grid-template-columns:1.1fr 1fr;gap:1rem}.list{overflow:hidden}.list>button{width:100%;display:flex;justify-content:space-between;gap:.8rem;text-align:left;padding:.85rem 1rem;border-bottom:1px solid #e2e8f0;background:#fff}.list>button:hover,.list>button.active{background:#ecfeff}.list button div{display:flex;flex-direction:column}.list small{color:#64748b}.empty{padding:1.2rem;color:#64748b}.detail h2{font-size:1.1rem;color:#082f49;margin:.8rem 0}.detail p{color:#475569}.detail dl{display:grid;grid-template-columns:90px 1fr;gap:.4rem;margin:1rem 0;font-size:.82rem}.detail dt{font-weight:800;color:#64748b}.detail textarea{width:100%;resize:vertical}.actions{display:flex;gap:.5rem;flex-wrap:wrap;margin-top:.8rem}@media(max-width:900px){.page{padding:1rem}.workspace{grid-template-columns:1fr}.stats{grid-template-columns:1fr}}</style>
